        public static string AutoSaveCompletedPrefix { get { return T("\u0412\u044b\u043f\u043e\u043b\u043d\u0435\u043d\u043e \u0430\u0432\u0442\u043e\u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435 ", "Autosave completed "); } }
    }
}
